<div class="page-header bookmarks-header"><div><h1 class="page-title">ลิงก์สำคัญ</h1><p class="text-muted">เก็บเว็บไซต์ที่ใช้บ่อยไว้ในที่เดียว</p></div><button class="btn btn-primary" id="bookmarkAddBtn" type="button">+ เพิ่มลิงก์</button></div>
<div class="bookmarks-grid" id="bookmarksGrid"><div class="empty-state">กำลังโหลด...</div></div>
<div class="modal-overlay" id="bookmarkModal" hidden><div class="modal-box" role="dialog" aria-modal="true" aria-labelledby="bookmarkTitle"><div class="modal-header"><h2 class="modal-title" id="bookmarkTitle">เพิ่มลิงก์</h2><button class="modal-close" type="button" id="bookmarkClose" aria-label="ปิด">&times;</button></div><form id="bookmarkForm" class="modal-body"><label class="form-label" for="bookmarkName">ชื่อเว็บ</label><input id="bookmarkName" class="form-control" maxlength="180" required placeholder="เช่น Google Drive"><label class="form-label" for="bookmarkUrl">URL</label><input id="bookmarkUrl" class="form-control" type="url" required placeholder="https://example.com"><label class="form-label" for="bookmarkCategory">หมวดหมู่</label><input id="bookmarkCategory" class="form-control" maxlength="80" value="ทั่วไป"><div class="form-actions"><button class="btn btn-ghost" type="button" id="bookmarkCancel">ยกเลิก</button><button class="btn btn-primary" type="submit">บันทึก</button></div></form></div></div>
